/**
 * Location params
 */
const { protocol, host, pathname } = window.location;
const needsNormalization = pathname.endsWith('/');
const normalizedPath = needsNormalization
  ? pathname.substring(0, pathname.length - 1)
  : pathname;

/**
 * Default configuration
 * @type {import('../types/index.d.ts').RestClientConfig}
 */
module.exports = {
  adapter: 'xhr',
  baseURL: `${protocol}//${host}${normalizedPath}/api`,
  method: 'get',
  timeout: 3000,
  responseType: 'json',
  maxRedirects: 0,
  sendCSRFToken: true,
  transitional: {
    // Needed to have the same behaviour between xhr and fetch adapters
    clarifyTimeoutError: true,
  },
};
